#[test]
fn test_options_extract_metadata_true() {
    // Extract metadata returns document metadata when enabled
    let html = r#"<html><head><title>Test Page</title><meta name='description' content='A test page'></head><body><p>Content</p></body></html>"#;
    let options_json = serde_json::json!({"extract_metadata": true});
    let options: ConversionOptions = serde_json::from_value(options_json).unwrap();
    let result = convert(html, Some(options.clone())).expect("should succeed");
    let metadata_document_title = result
        .metadata
        .document
        .title
        .as_ref()
        .map(|v| v.to_string())
        .unwrap_or_default();
    let metadata_document_description = result
        .metadata
        .document
        .description
        .as_ref()
        .map(|v| v.to_string())
        .unwrap_or_default();
    assert!(result.content.is_some(), "expected content to be present");
    assert_eq!(
        metadata_document_title.to_string().as_str().trim(),
        r#"Test Page"#,
        "equals assertion failed"
    );
    assert_eq!(
        metadata_document_description.to_string().as_str().trim(),
        r#"A test page"#,
        "equals assertion failed"
    );
}

