fn test_options_preprocessing_enabled_false_skips_cleanup() {
    // Disabling preprocessing entirely preserves elements the standard preset would remove
    let html = r#"<nav>NavSection</nav><p>Paragraph</p>"#;
    let options_json = serde_json::json!({"preprocessing": {"enabled": false}});
    let options: ConversionOptions = serde_json::from_value(options_json).unwrap();
    let result = convert(html, Some(options.clone())).expect("should succeed");
    let content = result.content.as_ref().map(|v| v.to_string()).unwrap_or_default();
    assert!(
        format!("{:?}", content).contains(r#"NavSection"#),
        "expected to contain: {}",
        r#"NavSection"#
    );
    assert!(
        format!("{:?}", content).contains(r#"Paragraph"#),
        "expected to contain: {}",
        r#"Paragraph"#
    );
}

