#[test]
fn test_options_whitespace_normalized() {
    // Normalized whitespace mode collapses multiple spaces
    let html = r#"<p>Text   with    extra   spaces.</p>"#;
    let options_json = serde_json::json!({"whitespace_mode": "Normalized"});
    let options: ConversionOptions = serde_json::from_value(options_json).unwrap();
    let result = convert(html, Some(options.clone())).expect("should succeed");
    let content = result.content.as_ref().map(|v| v.to_string()).unwrap_or_default();
    assert!(!content.is_empty(), "expected non-empty value");
    assert!(
        format!("{:?}", content).contains(r#"Text"#),
        "expected to contain: {}",
        r#"Text"#
    );
    assert!(
        format!("{:?}", content).contains(r#"with"#),
        "expected to contain: {}",
        r#"with"#
    );
    assert!(
        format!("{:?}", content).contains(r#"extra"#),
        "expected to contain: {}",
        r#"extra"#
    );
    assert!(
        format!("{:?}", content).contains(r#"spaces."#),
        "expected to contain: {}",
        r#"spaces."#
    );
}

